package com.google.gson.examples.android;

import static org.mockito.ArgumentMatchers.anyInt;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.spy;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

import android.os.Bundle;
import android.widget.TextView;

import com.google.gson.examples.android.model.Cart;
import java.lang.reflect.Method;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class GsonProguardExampleActivityTest {

  private GsonProguardExampleActivity activity;
  private TextView mockTextView;

  @BeforeEach
  public void setUp() {
    activity = spy(new GsonProguardExampleActivity());

    // Mock findViewById to return a mocked TextView
    mockTextView = mock(TextView.class);
    when(activity.findViewById(anyInt())).thenReturn(mockTextView);

    // Mock setContentView to do nothing
    Mockito.doNothing().when(activity).setContentView(anyInt());
  }

  @Test
  public void testOnCreate_callsExpectedMethods_setsTextViewTextAndInvalidates() throws Exception {
    // Prepare a mock Bundle
    Bundle mockBundle = mock(Bundle.class);

    // Create a sample Cart object
    Cart sampleCart = new Cart();

    // Use reflection to mock the private buildCart method to return sampleCart
    Method buildCartMethod = GsonProguardExampleActivity.class.getDeclaredMethod("buildCart");
    buildCartMethod.setAccessible(true);

    // Mock private method buildCart using Mockito's spy and reflection
    Mockito.doReturn(sampleCart).when(activity).buildCart();

    // Call onCreate
    activity.onCreate(mockBundle);

    // Verify setContentView called with R.layout.main (use actual int value)
    verify(activity).setContentView(getLayoutMain());

    // Verify findViewById called with R.id.tv (use actual int value)
    verify(activity).findViewById(getIdTv());

    // Verify TextView setText called once with any String
    verify(mockTextView).setText(Mockito.anyString());

    // Verify TextView invalidate called once
    verify(mockTextView).invalidate();
  }

  // Helper methods to provide R.layout.main and R.id.tv values
  private int getLayoutMain() {
    // return the int value for R.layout.main
    // You need to replace this with the actual value from your R class
    return 0x7f0a0000; // example placeholder value
  }

  private int getIdTv() {
    // return the int value for R.id.tv
    // You need to replace this with the actual value from your R class
    return 0x7f0b0000; // example placeholder value
  }
}
